import{_ as c,C as n,c as h,o as t,R as i,b as l,w as e,a as r,G as d,a1 as s}from"./chunks/framework.Dxoqk0BT.js";const p="/img/misc-410-1.png",u="/img/misc-410-2.png",S=JSON.parse('{"title":"Cookie 测试分析","description":"","frontmatter":{},"headers":[],"relativePath":"misc/410.md","filePath":"misc/410.md"}'),g={name:"misc/410.md"};function m(k,o,E,C,A,b){const a=n("Mermaid");return t(),h("div",null,[o[2]||(o[2]=i('<h1 id="cookie-测试分析" tabindex="-1">Cookie 测试分析 <a class="header-anchor" href="#cookie-测试分析" aria-label="Permalink to &quot;Cookie 测试分析&quot;">​</a></h1><h2 id="cookie-的生命周期" tabindex="-1">Cookie 的生命周期 <a class="header-anchor" href="#cookie-的生命周期" aria-label="Permalink to &quot;Cookie 的生命周期&quot;">​</a></h2><h3 id="会话期-cookie" tabindex="-1">会话期 Cookie <a class="header-anchor" href="#会话期-cookie" aria-label="Permalink to &quot;会话期 Cookie&quot;">​</a></h3><p>会话期 Cookie 会在当前会话结束时删除。浏览器自行定义&quot;当前会话&quot;的结束时间，部分浏览器在重启时会使用<strong>会话恢复</strong>功能，这可能导致会话 Cookie 无限延长。</p><h3 id="持久性-cookie" tabindex="-1">持久性 Cookie <a class="header-anchor" href="#持久性-cookie" aria-label="Permalink to &quot;持久性 Cookie&quot;">​</a></h3><p>持久性 Cookie 在以下两种情况之一发生时被删除：</p><ul><li>到达 <code>Expires</code> 属性指定的过期日期</li><li>超过 <code>Max-Age</code> 属性指定的有效期（单位：秒）</li></ul><h2 id="同源与跨站的区别" tabindex="-1">同源与跨站的区别 <a class="header-anchor" href="#同源与跨站的区别" aria-label="Permalink to &quot;同源与跨站的区别&quot;">​</a></h2><h3 id="同源-same-origin" tabindex="-1">同源（Same-Origin） <a class="header-anchor" href="#同源-same-origin" aria-label="Permalink to &quot;同源（Same-Origin）&quot;">​</a></h3><p>同源策略要求<strong>协议、域名和端口</strong>三者完全相同。</p><p>示例：<code>https://example.com:443</code> 与 <code>https://example.com:443</code> 是同源</p><h3 id="跨站-cross-site" tabindex="-1">跨站（Cross-Site） <a class="header-anchor" href="#跨站-cross-site" aria-label="Permalink to &quot;跨站（Cross-Site）&quot;">​</a></h3><p>跨站的判定标准更宽松，由<strong>可注册域名 + 协议</strong>确定。即二级域名或端口不同也属于同一站点。</p><p>示例：</p><ul><li><code>https://a.example.com</code> 与 <code>https://b.example.com</code> 是同站点</li><li><code>https://example.com:3000</code> 与 <code>https://example.com:8080</code> 是同站点</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Cookie 的 <code>SameSite</code> 属性指的就是&quot;同站点&quot;，而非&quot;同源&quot;。</p></div><h2 id="chrome-对-cookie-的重要变更" tabindex="-1">Chrome 对 Cookie 的重要变更 <a class="header-anchor" href="#chrome-对-cookie-的重要变更" aria-label="Permalink to &quot;Chrome 对 Cookie 的重要变更&quot;">​</a></h2><ul><li><strong>Chrome 80</strong>：将 Cookie 的 <code>SameSite</code> 属性默认值从 <code>None</code> 改为 <code>Lax</code></li><li><strong>2024 Q1</strong>：Chrome 开始对 1% 的用户禁用第三方 Cookie（逐步推进中）</li></ul><h2 id="同源策略-same-origin-policy" tabindex="-1">同源策略（Same-Origin Policy） <a class="header-anchor" href="#同源策略-same-origin-policy" aria-label="Permalink to &quot;同源策略（Same-Origin Policy）&quot;">​</a></h2><p>同源策略是浏览器的核心安全机制，限制了不同源之间的文档或脚本交互。</p><h3 id="受同源策略影响的功能" tabindex="-1">受同源策略影响的功能 <a class="header-anchor" href="#受同源策略影响的功能" aria-label="Permalink to &quot;受同源策略影响的功能&quot;">​</a></h3><ol><li><p><strong>XMLHttpRequest / Fetch API</strong></p><ul><li>默认只能向同源服务器发起请求</li><li>跨域请求需要通过 CORS（跨域资源共享）实现</li></ul></li><li><p><strong>DOM 访问</strong></p><ul><li>不同源的文档无法访问彼此的 DOM 元素</li></ul></li><li><p><strong>Cookie</strong></p><ul><li>浏览器为每个源独立存储 Cookie</li><li>不同源之间无法直接访问彼此的 Cookie</li></ul></li><li><p><strong>Storage API</strong></p><ul><li><code>localStorage</code> 和 <code>sessionStorage</code> 只能被同源脚本访问</li></ul></li><li><p><strong>iframe 嵌入</strong></p><ul><li>嵌入的 iframe 无法访问父文档内容（除非同源）</li></ul></li><li><p><strong>IndexedDB</strong></p><ul><li>只有同源脚本才能访问对应的数据库</li></ul></li><li><p><strong>Service Workers</strong></p><ul><li>只能拦截和处理同源请求</li></ul></li><li><p><strong>Web Workers</strong></p><ul><li>只能加载同源脚本</li></ul></li><li><p><strong>跨窗口通信</strong></p><ul><li>虽然 <code>window.postMessage</code> 允许跨域通信，但需要验证消息来源</li></ul></li></ol><h3 id="跨域解决方案" tabindex="-1">跨域解决方案 <a class="header-anchor" href="#跨域解决方案" aria-label="Permalink to &quot;跨域解决方案&quot;">​</a></h3><p>尽管同源策略提高了安全性，但实际开发中常需要跨域访问。常见解决方案：</p><ul><li><strong>CORS</strong>（跨域资源共享）：最标准和推荐的方式</li><li><strong>JSONP</strong>：利用 <code>&lt;script&gt;</code> 标签不受跨域限制的特性（仅支持 GET）</li><li><strong>代理服务器</strong>：通过同源服务器转发请求</li></ul><h2 id="cors-详解" tabindex="-1">CORS 详解 <a class="header-anchor" href="#cors-详解" aria-label="Permalink to &quot;CORS 详解&quot;">​</a></h2><p>CORS 由<strong>服务器</strong>决定是否允许跨域请求。请求分为两类：</p><h3 id="简单请求" tabindex="-1">简单请求 <a class="header-anchor" href="#简单请求" aria-label="Permalink to &quot;简单请求&quot;">​</a></h3><h4 id="判定规则" tabindex="-1">判定规则 <a class="header-anchor" href="#判定规则" aria-label="Permalink to &quot;判定规则&quot;">​</a></h4><p>同时满足以下所有条件：</p><ol><li><strong>请求方法</strong>：<code>GET</code>、<code>HEAD</code> 或 <code>POST</code></li><li><strong>Content-Type</strong>（仅针对 POST）： <ul><li><code>application/x-www-form-urlencoded</code>（表单提交，URL 编码）</li><li><code>multipart/form-data</code>（文件上传）</li><li><code>text/plain</code>（纯文本）</li></ul></li><li><strong>请求头</strong>：无自定义 Header</li></ol><h4 id="请求流程" tabindex="-1">请求流程 <a class="header-anchor" href="#请求流程" aria-label="Permalink to &quot;请求流程&quot;">​</a></h4>',32)),(t(),l(s,null,{default:e(()=>[d(a,{id:"mermaid-287",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20%E6%B5%8F%E8%A7%88%E5%99%A8-%3E%3E%E6%9C%8D%E5%8A%A1%E5%99%A8%3A%20%E7%9B%B4%E6%8E%A5%E5%8F%91%E9%80%81%E8%AF%B7%E6%B1%82%EF%BC%88%E8%87%AA%E5%8A%A8%E5%B8%A6%20Origin%20%E5%A4%B4%EF%BC%89%0A%20%20%20%20%E6%9C%8D%E5%8A%A1%E5%99%A8-%3E%3E%E6%B5%8F%E8%A7%88%E5%99%A8%3A%20%E8%BF%94%E5%9B%9E%20Access-Control-Allow-Origin%0A%20%20%20%20%E6%B5%8F%E8%A7%88%E5%99%A8-%3E%3E%E6%B5%8F%E8%A7%88%E5%99%A8%3A%20%E6%A0%A1%E9%AA%8C%E6%98%AF%E5%90%A6%E5%85%81%E8%AE%B8%E8%B7%A8%E5%9F%9F%0A"})]),fallback:e(()=>[...o[0]||(o[0]=[r(" Loading... ",-1)])]),_:1})),o[3]||(o[3]=i('<ol><li>浏览器直接发送请求，请求头自动携带 <code>Origin</code>（包含协议、域名、端口）</li><li>服务器检查 <code>Access-Control-Allow-Origin</code> 配置： <ul><li>匹配请求来源或设置为 <code>*</code>：允许跨域</li><li>不匹配：浏览器报错</li></ul></li></ol><h4 id="cookie-携带规则" tabindex="-1">Cookie 携带规则 <a class="header-anchor" href="#cookie-携带规则" aria-label="Permalink to &quot;Cookie 携带规则&quot;">​</a></h4><table><thead><tr><th>服务端设置</th><th>客户端设置</th><th>结果</th></tr></thead><tbody><tr><td>未设置 <code>Access-Control-Allow-Credentials</code></td><td><code>credentials: &#39;include&#39;</code></td><td>❌ 跨域报错，但 Cookie 会携带且服务器能收到</td></tr><tr><td>设置 <code>Access-Control-Allow-Credentials: true</code></td><td><code>credentials: &#39;include&#39;</code></td><td>✅ Cookie 正常携带</td></tr></tbody></table><h3 id="非简单请求-预检请求" tabindex="-1">非简单请求（预检请求） <a class="header-anchor" href="#非简单请求-预检请求" aria-label="Permalink to &quot;非简单请求（预检请求）&quot;">​</a></h3><p>不满足简单请求条件的都是非简单请求，如：</p><ul><li>使用 <code>PUT</code>、<code>DELETE</code>、<code>PATCH</code> 等方法</li><li><code>Content-Type</code> 为 <code>application/json</code></li><li>携带自定义请求头</li></ul><h4 id="非简单请求流程" tabindex="-1">非简单请求流程 <a class="header-anchor" href="#非简单请求流程" aria-label="Permalink to &quot;非简单请求流程&quot;">​</a></h4>',7)),(t(),l(s,null,{default:e(()=>[d(a,{id:"mermaid-380",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20%E6%B5%8F%E8%A7%88%E5%99%A8-%3E%3E%E6%9C%8D%E5%8A%A1%E5%99%A8%3A%201.%20OPTIONS%20%E9%A2%84%E6%A3%80%E8%AF%B7%E6%B1%82%0A%20%20%20%20%E6%9C%8D%E5%8A%A1%E5%99%A8-%3E%3E%E6%B5%8F%E8%A7%88%E5%99%A8%3A%202.%20%E8%BF%94%E5%9B%9E%E5%85%81%E8%AE%B8%E7%9A%84%E6%96%B9%E6%B3%95%2F%E5%A4%B4%E9%83%A8%E7%AD%89%0A%20%20%20%20%E6%B5%8F%E8%A7%88%E5%99%A8-%3E%3E%E6%B5%8F%E8%A7%88%E5%99%A8%3A%203.%20%E6%A0%A1%E9%AA%8C%E6%98%AF%E5%90%A6%E6%BB%A1%E8%B6%B3%E6%9D%A1%E4%BB%B6%0A%20%20%20%20%E6%B5%8F%E8%A7%88%E5%99%A8-%3E%3E%E6%9C%8D%E5%8A%A1%E5%99%A8%3A%204.%20%E5%8F%91%E9%80%81%E5%AE%9E%E9%99%85%E8%AF%B7%E6%B1%82%EF%BC%88%E8%8B%A5%E6%A0%A1%E9%AA%8C%E9%80%9A%E8%BF%87%EF%BC%89%0A"})]),fallback:e(()=>[...o[1]||(o[1]=[r(" Loading... ",-1)])]),_:1})),o[4]||(o[4]=i('<h4 id="预检请求-options" tabindex="-1">预检请求（OPTIONS） <a class="header-anchor" href="#预检请求-options" aria-label="Permalink to &quot;预检请求（OPTIONS）&quot;">​</a></h4><p>请求头包含：</p><ul><li><code>Origin</code>：请求来源</li><li><code>Access-Control-Request-Method</code>：实际请求将使用的方法</li><li><code>Access-Control-Request-Headers</code>：实际请求将携带的自定义头</li><li><strong>不包含 Cookie</strong></li></ul><p>响应头：</p><ul><li><code>Access-Control-Allow-Origin</code>：允许的来源</li><li><code>Access-Control-Allow-Methods</code>：允许的方法（默认 <code>GET</code>、<code>HEAD</code>、<code>POST</code>）</li><li><code>Access-Control-Allow-Headers</code>：允许的自定义头</li><li><code>Access-Control-Max-Age</code>：预检结果缓存时间</li><li><code>Access-Control-Allow-Credentials</code>：是否允许携带凭证</li></ul><p>响应状态码通常为 <code>204 No Content</code></p><h4 id="非简单请求的-cookie-携带规则" tabindex="-1">非简单请求的 Cookie 携带规则 <a class="header-anchor" href="#非简单请求的-cookie-携带规则" aria-label="Permalink to &quot;非简单请求的 Cookie 携带规则&quot;">​</a></h4><p>必须<strong>同时满足</strong>以下条件才能携带 Cookie：</p><ul><li>服务端设置 <code>Access-Control-Allow-Credentials: true</code></li><li>客户端设置 <code>credentials: &#39;include&#39;</code></li></ul><h2 id="cookie-规则详解" tabindex="-1">Cookie 规则详解 <a class="header-anchor" href="#cookie-规则详解" aria-label="Permalink to &quot;Cookie 规则详解&quot;">​</a></h2><h3 id="_5-条核心规则" tabindex="-1">5 条核心规则 <a class="header-anchor" href="#_5-条核心规则" aria-label="Permalink to &quot;5 条核心规则&quot;">​</a></h3><ol><li><p><strong>携带规则</strong> 客户端只能携带<strong>请求 URL 所在域及其父域</strong>的 Cookie</p></li><li><p><strong>读写规则</strong> 客户端 JavaScript 只能读写<strong>当前页面 URL 所在域及其父域</strong>的 Cookie</p></li><li><p><strong>非跨域资源请求</strong></p><ul><li><code>&lt;img&gt;</code>、<code>&lt;link&gt;</code>、<code>&lt;script&gt;</code> 等标签发起的 GET 请求会携带对应域的 Cookie</li><li>图片请求不受跨域限制（CORS）</li><li>Canvas 使用跨域图片时受限？（需设置 <code>crossorigin</code> 属性）</li></ul></li><li><p><strong>服务端设置规则</strong> 服务器只能为<strong>自己所在域或父域</strong>设置 Cookie</p><p>示例：<code>m.qq.com</code> 的服务器只能设置 <code>Domain</code> 为：</p><ul><li><code>.m.qq.com</code>（当前域）</li><li><code>.qq.com</code>（父域）</li></ul></li><li><p><strong>SameSite 默认行为</strong> Chrome 80+ 默认 <code>SameSite=Lax</code>：</p><ul><li>跨站请求默认不携带 Cookie</li><li>服务器的 <code>Set-Cookie</code> 在跨站场景下无效</li><li>响应头会显示，但浏览器不会存储</li></ul></li></ol><p><img src="'+p+'" alt="SameSite"></p><p><img src="'+u+'" alt="SameSite2"></p><h2 id="cookie-在不同场景下的行为" tabindex="-1">Cookie 在不同场景下的行为 <a class="header-anchor" href="#cookie-在不同场景下的行为" aria-label="Permalink to &quot;Cookie 在不同场景下的行为&quot;">​</a></h2><h3 id="同源场景" tabindex="-1">同源场景 <a class="header-anchor" href="#同源场景" aria-label="Permalink to &quot;同源场景&quot;">​</a></h3><p>✅ 执行规则 1、规则 4</p><h3 id="跨域-不同源-场景" tabindex="-1">跨域（不同源）场景 <a class="header-anchor" href="#跨域-不同源-场景" aria-label="Permalink to &quot;跨域（不同源）场景&quot;">​</a></h3><h4 id="未设置-cors" tabindex="-1">未设置 CORS <a class="header-anchor" href="#未设置-cors" aria-label="Permalink to &quot;未设置 CORS&quot;">​</a></h4><table><thead><tr><th>请求类型</th><th>行为</th></tr></thead><tbody><tr><td>简单请求</td><td>❌ 浏览器报错<br>✅ 但仍执行规则 1、4、5（Cookie 会携带）</td></tr><tr><td>非简单请求</td><td>❌ 直接报错，不发送实际请求</td></tr></tbody></table><h4 id="设置-cors" tabindex="-1">设置 CORS <a class="header-anchor" href="#设置-cors" aria-label="Permalink to &quot;设置 CORS&quot;">​</a></h4><table><thead><tr><th>服务端 Credentials</th><th>客户端 credentials</th><th>结果</th></tr></thead><tbody><tr><td>❌ 未设置</td><td>✅ <code>include</code></td><td>❌ 报错</td></tr><tr><td>✅ <code>true</code></td><td>❌ 未设置</td><td>✅ 不报错<br>❌ 不携带 Cookie<br>❌ <code>Set-Cookie</code> 无效<br>⚠️ Chrome 开发者工具显示错误</td></tr><tr><td>✅ <code>true</code></td><td>✅ <code>include</code></td><td>✅ 正常工作<br>✅ 执行规则 1、4、5</td></tr></tbody></table><h2 id="cookie-访问权限对照表" tabindex="-1">Cookie 访问权限对照表 <a class="header-anchor" href="#cookie-访问权限对照表" aria-label="Permalink to &quot;Cookie 访问权限对照表&quot;">​</a></h2><p>以 <code>m.qq.com</code> 为当前页面，测试对不同域的 Cookie 访问：</p><table><thead><tr><th>操作</th><th>.m.qq.com</th><th>.qq.com</th><th>.sub.m.qq.com</th><th>.n.qq.com</th><th>x.com</th></tr></thead><tbody><tr><td><strong>GET/POST 请求自动携带 Cookie</strong></td><td>✅</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>服务器读写 Cookie</strong></td><td>✅</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>JavaScript 读写 Cookie</strong></td><td>✅</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><strong>HTML 加载图片资源</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>加载图片时携带 Cookie</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>JavaScript 读取图片数据</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅*</td></tr></tbody></table><p>* 跨域图片需要设置 CORS 才能被 Canvas 读取像素数据</p><h2 id="最佳实践建议" tabindex="-1">最佳实践建议 <a class="header-anchor" href="#最佳实践建议" aria-label="Permalink to &quot;最佳实践建议&quot;">​</a></h2><h3 id="安全设置" tabindex="-1">安全设置 <a class="header-anchor" href="#安全设置" aria-label="Permalink to &quot;安全设置&quot;">​</a></h3><ol><li><p><strong>使用 SameSite 属性</strong></p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Set-Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sessionid=xxx; SameSite=Strict; Secure; HttpOnly</span></span></code></pre></div></li><li><p><strong>敏感 Cookie 设置 HttpOnly</strong> 防止 XSS 攻击窃取 Cookie</p></li><li><p><strong>HTTPS 环境使用 Secure 标志</strong> 确保 Cookie 只通过 HTTPS 传输</p></li></ol><h3 id="cors-配置" tabindex="-1">CORS 配置 <a class="header-anchor" href="#cors-配置" aria-label="Permalink to &quot;CORS 配置&quot;">​</a></h3><ol><li><p><strong>避免使用通配符 <code>*</code></strong> 明确指定允许的来源</p></li><li><p><strong>谨慎开启 Credentials</strong> 只在必要时允许携带凭证</p></li><li><p><strong>设置合理的 <code>Max-Age</code></strong> 减少预检请求次数，提升性能</p></li></ol><h3 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h3><ol><li><p><strong>Chrome DevTools</strong></p><ul><li>Network 面板查看请求头/响应头</li><li>Application 面板查看 Cookie 存储</li><li>Console 查看 CORS 错误详情</li></ul></li><li><p><strong>常见错误排查</strong></p><ul><li>Cookie 未携带：检查 Domain、SameSite、CORS 配置</li><li>Set-Cookie 失效：检查 SameSite、跨站场景、Secure 标志</li></ul></li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/HTTP/Cookies" target="_blank" rel="noreferrer">MDN - HTTP Cookies</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/Security/Same-origin_policy" target="_blank" rel="noreferrer">MDN - 同源策略</a></li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/HTTP/CORS" target="_blank" rel="noreferrer">MDN - CORS</a></li><li><a href="https://www.chromium.org/updates/same-site/" target="_blank" rel="noreferrer">Chrome SameSite 更新说明</a></li></ul>',35))])}const f=c(g,[["render",m]]);export{S as __pageData,f as default};
